sql:
SELECT regulatory_agency, COUNT(drug_id) AS num_of_drugs_approved
FROM drugs
GROUP BY regulatory_agency;

SELECT DISTINCT d.drug_name
FROM drugs d
INNER JOIN drug_updates du ON d.drug_id = du.drug_id;

SELECT d.drug_name, du.new_approved_use
FROM drugs d
INNER JOIN drug_updates du ON d.drug_id = du.drug_id;

SELECT COUNT(DISTINCT drug_id) 
FROM drug_updates 
WHERE new_approved_use LIKE '%when used in combination with metformin%';

SELECT d.drug_id, d.drug_name
FROM drugs d
JOIN drug_updates u ON d.drug_id = u.drug_id
WHERE u.update_date = (
    SELECT MAX(update_date) FROM drug_updates
);

external_knowledge:
- "Original uses" refer to the initial FDA-approved uses that were given to the drugs when they were first approved;
- "New approved uses" indicate any additional uses or indications that were later approved by the FDA;
- "Most recent update dates" refer to the dates on which the latest changes to the drug's approved uses were recorded.

sql:
SELECT drug_name, approval_date 
FROM drugs 
ORDER BY approval_date ASC;
